// Flow composition — build reusable pipelines with >>

fn trim(s) { return s.trim() }
fn lower(s) { return s.toLowerCase() }
fn exclaim(s) { return "${s}!" }

// >> creates a reusable pipeline
shout >> trim lower exclaim

print shout("  Hello World  ")
print shout("  KimchiLang  ")

fn double(x) { return x * 2 }
fn addTen(x) { return x + 10 }

transform >> double addTen
print "transform(5) = ${transform(5)}"
print "transform(3) = ${transform(3)}"

// Memoization — built-in caching with memo

memo fib(n) {
  return match n {
    0 => 0
    1 => 1
    _ => fib(n - 1) + fib(n - 2)
  }
}

print "fib(10) = ${fib(10)}"
print "fib(20) = ${fib(20)}"
print "fib(30) = ${fib(30)}"
print "fib(40) = ${fib(40)}"
